"use client";
import * as React from "react";
import { cardAnatomy } from "@tessera/core";

export interface CardRootProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Adds hover affordance for clickable/linkable cards. */
  interactive?: boolean;
}

function CardRoot({ interactive, children, ...rest }: CardRootProps) {
  return (
    <div {...cardAnatomy.attrs("root")} data-interactive={interactive || undefined} {...rest}>
      {children}
    </div>
  );
}

function CardHeader(props: React.HTMLAttributes<HTMLDivElement>) {
  return <div {...cardAnatomy.attrs("header")} {...props} />;
}

function CardTitle(props: React.HTMLAttributes<HTMLHeadingElement>) {
  return <h3 {...cardAnatomy.attrs("title")} style={{ margin: 0 }} {...props} />;
}

function CardDescription(props: React.HTMLAttributes<HTMLParagraphElement>) {
  return <p {...cardAnatomy.attrs("description")} style={{ margin: 0 }} {...props} />;
}

function CardContent(props: React.HTMLAttributes<HTMLDivElement>) {
  return <div {...cardAnatomy.attrs("content")} {...props} />;
}

function CardFooter(props: React.HTMLAttributes<HTMLDivElement>) {
  return <div {...cardAnatomy.attrs("footer")} {...props} />;
}

export const Card = {
  Root: CardRoot,
  Header: CardHeader,
  Title: CardTitle,
  Description: CardDescription,
  Content: CardContent,
  Footer: CardFooter,
};

@layer tessera.recipes {
  [data-scope="card"][data-part="root"] {
    display: flex;
    flex-direction: column;
    background: var(--ts-bg-surface);
    border: 1px solid var(--ts-border-muted);
    border-radius: var(--ts-radius-xl);
    overflow: hidden;
  }

  [data-scope="card"][data-part="root"][data-interactive] {
    transition:
      border-color var(--ts-duration-fast) var(--ts-easing-standard),
      transform var(--ts-duration-fast) var(--ts-easing-standard);
  }

  [data-scope="card"][data-part="root"][data-interactive]:hover {
    border-color: var(--ts-border-strong);
    transform: translateY(-1px);
  }

  [data-scope="card"][data-part="header"] {
    display: flex;
    flex-direction: column;
    gap: var(--ts-space-1);
    padding: var(--ts-space-5) var(--ts-space-5) 0;
  }

  [data-scope="card"][data-part="title"] {
    font-size: var(--ts-font-size-md);
    font-weight: var(--ts-font-weight-semibold);
    color: var(--ts-fg-default);
  }

  [data-scope="card"][data-part="description"] {
    font-size: var(--ts-font-size-sm);
    color: var(--ts-fg-muted);
  }

  [data-scope="card"][data-part="content"] {
    padding: var(--ts-space-4) var(--ts-space-5);
    font-size: var(--ts-font-size-sm);
    color: var(--ts-fg-default);
    flex: 1;
  }

  [data-scope="card"][data-part="footer"] {
    display: flex;
    align-items: center;
    gap: var(--ts-space-2);
    padding: var(--ts-space-4) var(--ts-space-5);
    border-top: 1px solid var(--ts-border-muted);
    background: var(--ts-bg-canvas);
  }
}
